import {
    Agent
} from "@cursor/sdk";

// 创建 AI Agent，指向「创作选题获取器」项目
const agent = await Agent.create({
    apiKey: 'crsr_4dc9fc96b5a6117e96ad198e0fb54fbf71897dc968cf03dceb1743f5a0d6831a',
    model: {
        id: "gpt-5.5"
    },
    // local: {
    //     cwd: "/Users/yupi/workflow/创作选题获取器"
    // },
});

// 一句话下达指令
const run = await agent.send("帮我获取今日 AI 领域的热门选题，并生成一个网页报告");

// 收集所有事件，打印到终端的同时保存到文件
const events = [];
for await (const event of run.stream()) {
    console.log(event);
    events.push(event);
}

// 把完整的事件记录保存为 JSON 文件，方便事后分析
const fs = await import("fs");
fs.writeFileSync("agent-output.json", JSON.stringify(events, null, 2));

